import React from 'react';
import { renderToStaticMarkup } from 'react-dom/server';
const loadUsers = async () => [{ id: 1, name: 'Ada' }];
async function Users() {
  const users = await loadUsers();
  return React.createElement('ul', null, users.map(user => React.createElement('li', { key: user.id }, user.name)));
}
const html = renderToStaticMarkup(await Users());
if (!html.includes('<li>Ada</li>')) throw new Error(html);
